Bash(php artisan tinker --execute="
\\$firmId = App\\Models\\Firm::first\(\)->id;
\\$matters = App\\Models\\Matter::where\('firm_id', \\$firmId\)
    ->with\(['tasks' => fn\(\\$q\) => \\$q->whereIn\('status', ['todo', 'in_progress']\)->whereNull\('completed_at'\)->orderBy\('due_date'\)]\)
    ->get\(\);

foreach \(\\$matters as \\$m\) {
    echo \\$m->name . PHP_EOL;
    echo '  next_step: ' . \(\\$m->next_step ?? 'null'\) . PHP_EOL;
    echo '  next_deadline: ' . \(\\$m->next_deadline ?? 'null'\) . PHP_EOL;
    echo '  tasks: ' . \\$m->tasks->count\(\) . PHP_EOL;
    foreach \(\\$m->tasks as \\$t\) {
        echo '    - ' . \\$t->title . ' | due=' . \(\\$t->due_date?->toDateString\(\) ?? 'null'\) . ' | status=' . \\$t->status . PHP_EOL;
    }
}
" 2>&1)
